INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES
('92cde9b2-868d-4168-8034-609081db7a5b', 'Intensive Literacy Intervention', 'Intervention', 'High-dosage, small-group or 1:1 intervention focusing on decoding, fluency, and comprehension for students significantly below grade level.', 'Evidence from targeted intervention studies shows accelerated growth when delivered with sufficient intensity and fidelity.', ARRAY['Accelerate reading growth','Close skill gaps','Improve comprehension']::text[], 'Daily 30–45 minute sessions for 12–24 weeks', ARRAY['Intervention materials','Progress monitoring tools','Training & coaching']::text[], '[{"name": "Diagnostic placement", "is_core": true, "description": "Pinpoint skill deficits to target instruction."}, {"name": "High-dosage small group", "is_core": true, "description": "Daily sessions with explicit instruction."}, {"name": "Cumulative review & practice", "is_core": true, "description": "Spiral practice to solidify learning."}, {"name": "Frequent progress monitoring", "is_core": true, "description": "Weekly tracking to adjust instruction."}]'::jsonb, '{"target_group": "The [number] students in grades [range] scoring more than 1.5 standard deviations below benchmark with inadequate response to prior intervention, reviewed to ensure no student group is over- or under-identified.", "problem_statement": "A small group of students remains far below grade level in reading despite receiving core instruction and standard interventions. Currently [number] students in grades [range] score more than 1.5 standard deviations below benchmark, and [X]% of them have shown flat or declining growth across two or more progress-monitoring cycles. These students need a fundamentally more intensive approach: smaller groups, more minutes, more precise diagnosis of skill gaps, and more frequent progress checks than our current intervention block provides.", "lagging_indicators": ["Rate of improvement versus goal line on progress monitoring", "Percent of students meeting intervention exit criteria", "Benchmark composite movement fall to spring", "Reading self-concept (student survey)"], "leading_indicators": ["Intervention sessions delivered versus scheduled (dosage)", "Group size held at or below [3 to 5] students", "Percent of sessions following the diagnostic-prescriptive plan", "Interventionist-classroom teacher communication touchpoints"], "measurement_timeline": ["Weekly progress monitoring with goal-line analysis", "Intervention plan review every 6 to 8 weeks with intensify-or-exit decisions", "Benchmark screening fall, winter, and spring", "Semester case review with families"]}'::jsonb),
('8b62dd48-8964-422d-b7d7-225fb1bb4c57', 'MTSS/RTI Framework', 'Framework', 'Tiered system providing increasing levels of support matched to student need using screening, progress monitoring, and data-based decision making.', 'Strong evidence for improved outcomes when high-quality core instruction, screening, and targeted interventions are implemented with fidelity.', ARRAY['Improve universal screening coverage','Increase responsiveness to interventions','Reduce special education referrals']::text[], 'Establish within a semester; refine continuously through data cycles', ARRAY['Screening tools','Progress monitoring probes','Intervention menu']::text[], '[{"name": "Universal screening", "is_core": true, "description": "At least 3x/year with high coverage."}, {"name": "Tiered intervention menu", "is_core": true, "description": "Evidence-based options matched to need."}, {"name": "Data meetings", "is_core": true, "description": "Regular team review and instructional adjustments."}, {"name": "Progress monitoring", "is_core": true, "description": "Weekly or biweekly measures to track growth."}, {"name": "Check & adjust", "is_core": false, "description": "Fidelity checks and refinements."}]'::jsonb, '{"target_group": "All students through universal screening (Tier 1); the approximately [X]% needing supplemental intervention (Tier 2) and [X]% needing intensive support (Tier 3), identified by shared data rules rather than teacher discretion alone.", "problem_statement": "Students who need more than core instruction are identified late, inconsistently, or not at all, and the support they receive depends more on which teacher they have than on their data. Currently [X]% of students receive some intervention, but entry and exit decisions lack shared criteria, intervention quality varies across grades, and [X]% of special education referrals show no documented intervention history. The result is students waiting to fail rather than receiving timely, layered support matched to need.", "lagging_indicators": ["Median student growth percentile, by tier and student group", "Percent of Tier 2 students returning to Tier 1 within a semester", "Special education referral and qualification rates", "Course failure or retention rates"], "leading_indicators": ["Percent of students screened within the screening window", "Percent of intervention groups meeting as scheduled", "Data-meeting attendance and decision-log completion", "Percent of interventions with progress monitoring at the planned frequency"], "measurement_timeline": ["Universal screening three times per year", "Biweekly progress monitoring for Tier 2, weekly for Tier 3", "Grade-level data meetings every 4 to 6 weeks with documented decisions", "Annual MTSS fidelity self-assessment"]}'::jsonb),
('1c5e8b01-c1e1-4328-862b-9b60dfde92dc', 'PBIS (Positive Behavioral Interventions and Supports)', 'Behavior', 'A multi-tiered framework emphasizing proactive strategies for defining, teaching, and supporting appropriate student behaviors.', 'Extensive evidence across hundreds of schools showing reductions in office discipline referrals and improvements in climate.', ARRAY['Reduce office discipline referrals','Increase instructional time','Improve school climate']::text[], 'School-wide rollout over 6–12 months with continuous data cycles', ARRAY['Behavior matrix posters','Acknowledgement system','Referral data tracker']::text[], '[{"name": "Behavior expectations matrix", "is_core": true, "description": "Define 3\u20135 positively stated expectations across settings."}, {"name": "Explicit teaching of expectations", "is_core": true, "description": "Direct instruction and practice of expected behaviors."}, {"name": "Acknowledgement system", "is_core": true, "description": "Consistent reinforcement of expected behaviors."}, {"name": "Data-based problem solving", "is_core": true, "description": "Monthly review of ODRs to target supports."}, {"name": "Classroom routines & corrections", "is_core": false, "description": "Active supervision, precorrections, and calm responses."}]'::jsonb, '{"target_group": "All students school-wide (Tier 1), with Tier 2 supports for the approximately [X]% of students with 2 to 5 referrals. Priority attention to [student groups] who are disproportionately referred under current practice.", "problem_statement": "Office discipline referrals (ODRs) are consuming instructional time and disproportionately affecting some student groups. Last year we logged [number] ODRs, averaging [X] per 100 students per month, with referrals concentrated in [settings such as hallways, cafeteria, transitions]. Students lose an estimated [X] minutes of instruction per referral, and our data show [student group] is referred at [X] times the rate of peers. Reactive discipline has not changed the pattern; we lack a school-wide system that teaches and reinforces expected behavior proactively.", "lagging_indicators": ["ODRs per 100 students per month", "Suspension rate, disaggregated by student group", "Instructional minutes recovered (referrals times average minutes)", "Student and staff school-climate survey scores"], "leading_indicators": ["Percent of staff teaching expectations weekly (walkthrough data)", "Acknowledgment-to-correction ratio (target 4:1)", "Percent of students who can state the school expectations", "Staff consistency in minor versus major referral definitions"], "measurement_timeline": ["Monthly ODR review by the implementation team, disaggregated by location, time, and student group", "Quarterly climate survey pulse (students and staff)", "Semester suspension and disproportionality analysis", "Annual full PBIS tiered fidelity inventory"]}'::jsonb),
('fa46924a-599d-4156-91bd-eaa4817b557f', 'Second Step Social-Emotional Learning', 'SEL', 'A structured SEL curriculum building self-management, relationship skills, and responsible decision-making.', 'Multiple randomized trials report improvements in prosocial behavior and reductions in problem behavior.', ARRAY['Increase prosocial behaviors','Improve self-regulation','Reduce disruptive incidents']::text[], 'Weekly lessons over 20–30 weeks with embedded practice', ARRAY['Lesson kits','Family engagement letters','Implementation guide']::text[], '[{"name": "Weekly explicit SEL lessons", "is_core": true, "description": "Scripted lessons with modeling and practice."}, {"name": "Embedded practice routines", "is_core": true, "description": "Daily prompts to generalize skills."}, {"name": "Reinforcement & reflection", "is_core": true, "description": "Acknowledge use of SEL skills; student reflection."}, {"name": "Family connection", "is_core": false, "description": "Send home practice activities."}]'::jsonb, '{"target_group": "All students in grades [range] receive core SEL lessons (Tier 1); students flagged by counselor referral or climate data receive small-group reinforcement. Attend to whether [student groups] access supports proportionally.", "problem_statement": "Students need stronger skills in self-regulation, problem solving, and peer relationships than our current approach builds. Behavior data show [number] peer-conflict incidents last [term], counselor referrals for emotional regulation have risen [X]% since [year], and on our climate survey only [X]% of students agreed that students at this school help each other. Teachers report losing instructional time to low-level conflict and dysregulation, and our SEL instruction is currently left to individual teacher initiative rather than a consistent, evidence-based curriculum.", "lagging_indicators": ["Peer-conflict incident rate", "Counselor referrals for regulation support", "Climate survey items on belonging and peer support", "Classroom instructional time lost to behavior (teacher estimate)"], "leading_indicators": ["Percent of classrooms delivering the weekly lesson as scheduled", "Student use of taught vocabulary and strategies (observation)", "Teacher-reported integration of skills outside lesson time", "Family awareness of monthly SEL focus (newsletter engagement)"], "measurement_timeline": ["Weekly lesson-completion tracking by grade", "Monthly incident-data review by the implementation team", "Climate survey fall and spring", "Semester review of counselor referral patterns"]}'::jsonb),
('7b50257a-cd7b-4bef-a310-e247298fa83b', 'Structured Literacy Program', 'Literacy', 'Systematic, explicit instruction in phonemic awareness, phonics, fluency, vocabulary, and comprehension aligned to the science of reading.', 'Strong evidence from meta-analyses (e.g., National Reading Panel, IES WWC) showing improved early decoding and long-term reading outcomes.', ARRAY['Improve decoding accuracy','Increase reading fluency','Boost comprehension on grade-level texts']::text[], 'Core implementation over 12–24 weeks with ongoing progress monitoring', ARRAY['Tiered materials set','Decodable texts','Screeners & progress monitors']::text[], '[{"name": "Explicit phonics routines", "is_core": true, "description": "Daily, systematic instruction of sound-spelling patterns with cumulative review."}, {"name": "Phonemic awareness practice", "is_core": true, "description": "Oral blending, segmenting, and manipulation activities."}, {"name": "Decodable text practice", "is_core": true, "description": "Controlled texts aligned to taught patterns for fluency."}, {"name": "Error correction routine", "is_core": true, "description": "Immediate corrective feedback with guided practice."}, {"name": "Vocabulary and background", "is_core": false, "description": "Pre-teach key vocabulary and build knowledge."}]'::jsonb, '{"target_group": "All K-2 students for core instruction (Tier 1), with priority intervention for the [number] students below benchmark on universal screening, disaggregated to ensure [student groups] are progressing proportionally.", "problem_statement": "Our youngest readers are not building the decoding and fluency foundation that later comprehension depends on. On the [fall/winter] universal screening, [X]% of K-2 students scored below benchmark in decoding and [X]% in oral reading fluency, against a district expectation of at least 80% at benchmark. The gap is widest for [student group], at [X]% below benchmark versus [X]% for peers. Our current core materials emphasize exposure over explicit, systematic instruction in phonemic awareness and phonics, and teachers report uneven preparation to deliver structured literacy practices.", "lagging_indicators": ["Universal screening composite (DIBELS, Acadience, or district measure)", "Percent at benchmark in decoding, by grade and student group", "Oral reading fluency growth (words correct per minute)", "Percent of intervention students closing to benchmark"], "leading_indicators": ["Percent of literacy blocks following the structured routine (walkthroughs)", "Teacher confidence in explicit phonics instruction (self-report)", "Student engagement during word work (observation)", "Weekly progress-monitoring completion rate"], "measurement_timeline": ["Weekly progress monitoring for intervention students", "Monthly grade-level data meetings on routine fidelity and student response", "Benchmark screening fall, winter, and spring", "Semester disproportionality check across student groups"]}'::jsonb)
